import Foundation

enum LogLevel: Int, Comparable, Sendable {
    case debug = 0, info, warning, error

    static func < (lhs: LogLevel, rhs: LogLevel) -> Bool { lhs.rawValue < rhs.rawValue }

    var label: String {
        switch self {
        case .debug: "DEBUG"
        case .info: "INFO"
        case .warning: "WARN"
        case .error: "ERROR"
        }
    }

    static func from(string: String) -> LogLevel {
        switch string.lowercased() {
        case "debug": .debug
        case "warning", "warn": .warning
        case "error": .error
        default: .info
        }
    }
}

final class FileLogger: Sendable {
    let filePath: String
    let minLevel: LogLevel
    private let maxBytes: UInt64 = 5 * 1024 * 1024 // 5 MB

    init(filePath: String, minLevel: LogLevel = .info) {
        self.filePath = filePath
        self.minLevel = minLevel
        let dir = (filePath as NSString).deletingLastPathComponent
        FileManager.default.createDirectory(atPath: dir, withIntermediateDirectories: true, attributes: nil)
    }

    func log(_ level: LogLevel, _ message: String, file: String = #file, line: Int = #line) {
        guard level >= minLevel else { return }
        let timestamp = ISO8601DateFormatter().string(from: Date())
        let entry = "[\(timestamp)] [\(level.label)] \(message)\n"
        append(entry)
    }

    // MARK: - Private

    private func append(_ entry: String) {
        guard let data = entry.data(using: .utf8) else { return }

        if !FileManager.default.fileExists(atPath: filePath) {
            FileManager.default.createFile(atPath: filePath, contents: nil)
        }

        rotateIfNeeded()

        guard let handle = FileHandle(forWritingAtPath: filePath) else { return }
        defer { handle.closeFile() }
        handle.seekToEndOfFile()
        handle.write(data)
    }

    private func rotateIfNeeded() {
        guard let attrs = try? FileManager.default.attributesOfItem(atPath: filePath),
              let size = attrs[.size] as? UInt64,
              size > maxBytes else { return }
        let backup = filePath + ".1"
        try? FileManager.default.removeItem(atPath: backup)
        try? FileManager.default.moveItem(atPath: filePath, toPath: backup)
        FileManager.default.createFile(atPath: filePath, contents: nil)
    }
}

// MARK: - Shared loggers

enum Loggers {
    private static let cacheDir: String = {
        let home = FileManager.default.homeDirectoryForCurrentUser.path
        return "\(home)/.cache/ai-usages-tracker"
    }()

    private static let level: LogLevel = {
        LogLevel.from(string: ProcessInfo.processInfo.environment["AI_TRACKER_LOG_LEVEL"] ?? "info")
    }()

    static let app = FileLogger(filePath: "\(cacheDir)/app.log", minLevel: level)
    static let claude = FileLogger(filePath: "\(cacheDir)/claude-usages-connector.log", minLevel: level)
}

